// =============================================
// Tiempos Unificado - Multi-Pestaña
// Lee todas las pestañas del archivo .xls,
// cada pestaña es una sección.
// =============================================

const XLSX = require('xlsx');

try {

// --- Obtener archivo binario ---
const binaryData = $input.first().binary;
if (!binaryData || !binaryData.data) {
  return [{ json: { valid: false, errorMessage: 'No se recibio archivo' } }];
}

const binaryObj = binaryData.data;
let fileName = binaryObj.fileName || 'upload.xls';
const buffer = await this.helpers.getBinaryDataBuffer(0, 'data');
const workbook = XLSX.read(buffer, { type: 'buffer' });
const sheetNames = workbook.SheetNames;

if (sheetNames.length === 0) {
  return [{ json: { valid: false, errorMessage: 'El archivo no tiene pestañas: ' + fileName } }];
}

// --- Funciones auxiliares ---
function esc(s) {
  return String(s || '').replace(/'/g, "''").trim();
}
function timeToDays(s) {
  if (s === undefined || s === null) return 'NULL::numeric';
  const str = String(s).trim();
  if (!str) return 'NULL::numeric';
  const m = str.match(/^(\d+):(\d{2})$/);
  if (!m) return 'NULL::numeric';
  return Math.round(((parseInt(m[1]) + parseInt(m[2]) / 60) / 24) * 10000) / 10000;
}

let fechaInicio = null;
let fechaFin = null;
let anio = null;
let mes = null;
const meses = ['','ENE','FEB','MAR','ABR','MAY','JUN','JUL','AGO','SEP','OCT','NOV','DIC'];

const secciones = [];
const todosExamenes = [];
const errores = [];

// --- Procesar cada pestaña ---
for (const sheetName of sheetNames) {
  const ws = workbook.Sheets[sheetName];
  const rows = XLSX.utils.sheet_to_json(ws, { header: 1 });

  if (rows.length < 9) {
    errores.push(sheetName + ': muy pocas filas (' + rows.length + ')');
    continue;
  }

  // Buscar fechas (primeras 15 filas, columnas 0-4)
  if (!fechaInicio) {
    outer: for (let i = 0; i < Math.min(rows.length, 15); i++) {
      for (let c = 0; c < 5; c++) {
        const val = String(rows[i]?.[c] || '');
        const m = val.match(/Fecha inicial:\s*(\d{2})\/(\d{2})\/(\d{4})\s+Fecha final:\s*(\d{2})\/(\d{2})\/(\d{4})/);
        if (m) {
          fechaInicio = m[3] + '-' + m[2] + '-' + m[1];
          fechaFin = m[6] + '-' + m[5] + '-' + m[4];
          anio = parseInt(m[3]);
          mes = meses[parseInt(m[2])];
          break outer;
        }
      }
    }
  }

  // Fila 5 = datos de la sección (index 5)
  const secRow = rows[5];
  if (!secRow || !secRow[0]) {
    errores.push(sheetName + ': no se encontro datos de seccion en fila 6');
    continue;
  }

  const seccionNombre = String(secRow[0]).trim();
  const secTotal = parseInt(secRow[1]) || 0;
  const secIngRes = String(secRow[2] || '').trim();
  const secResVal = String(secRow[3] || '').trim();
  const secIngVal = String(secRow[4] || '').trim();
  const secValImp = String(secRow[5] || '').trim();
  const secIngImp = String(secRow[6] || '').trim();

  secciones.push({
    seccion: seccionNombre,
    total: secTotal,
    ingRes: secIngRes,
    resVal: secResVal,
    ingVal: secIngVal,
    valImp: secValImp,
    ingImp: secIngImp
  });

  // Examenes: desde fila 9 (index 9) hasta "Total"
  for (let i = 9; i < rows.length; i++) {
    const row = rows[i];
    if (!row || !row[0]) continue;
    const name = String(row[0]).trim();
    if (/^total$/i.test(name)) break;
    const tVal = row[1];
    if (tVal === undefined || tVal === null || String(tVal).trim() === '') continue;
    todosExamenes.push({
      seccionPadre: seccionNombre,
      examen: name,
      total: parseInt(tVal) || 0,
      ingRes: String(row[2] || '').trim(),
      resVal: String(row[3] || '').trim(),
      ingVal: String(row[4] || '').trim(),
      valImp: String(row[5] || '').trim(),
      ingImp: String(row[6] || '').trim()
    });
  }
}

if (!fechaInicio) {
  const debug = workbook.SheetNames.slice(0, 2).map(sn => {
    const ws = workbook.Sheets[sn];
    const rows = XLSX.utils.sheet_to_json(ws, { header: 1 });
    return { sheet: sn, filas: rows.slice(0, 5).map(r => (r || []).slice(0, 5)) };
  });
  return [{ json: { valid: false, errorMessage: 'No se encontro rango de fechas en ninguna pestaña de ' + fileName, debug: debug } }];
}

if (secciones.length === 0) {
  return [{ json: { valid: false, errorMessage: 'No se encontraron secciones validas en ' + fileName } }];
}

// --- SQL: Periodo + Secciones ---
const secVals = secciones.map(s =>
  `('${esc(s.seccion)}', ${s.total}, '${esc(s.ingRes)}', '${esc(s.resVal)}', '${esc(s.ingVal)}', '${esc(s.valImp)}', '${esc(s.ingImp)}', ${timeToDays(s.ingRes)}, ${timeToDays(s.resVal)}, ${timeToDays(s.ingVal)}, ${timeToDays(s.valImp)}, ${timeToDays(s.ingImp)})`
).join(',\n    ');

const sectionSQL = `
WITH new_periodo AS (
  INSERT INTO periodos (fecha_inicio, fecha_fin, mes, anio, archivo_origen)
  VALUES ('${fechaInicio}', '${fechaFin}', '${mes}', ${anio}, '${esc(fileName)}')
  ON CONFLICT (fecha_inicio, fecha_fin)
  DO UPDATE SET archivo_origen = EXCLUDED.archivo_origen
  RETURNING id
)
INSERT INTO tiempos_seccion (
  periodo_id, seccion, total_examenes,
  ingreso_resultado_horas, resultado_validacion_horas, ingreso_validacion_horas,
  validacion_impresion_horas, ingreso_impresion_horas,
  ingreso_resultado_dias, resultado_validacion_dias, ingreso_validacion_dias,
  validacion_impresion_dias, ingreso_impresion_dias,
  meta_dias, eficacia
)
SELECT
  np.id, v.seccion, v.total_examenes,
  v.ir_h, v.rv_h, v.iv_h, v.vi_h, v.ii_h,
  v.ir_d, v.rv_d, v.iv_d, v.vi_d, v.ii_d,
  m.meta_dias,
  CASE WHEN v.ii_d > 0 AND m.meta_dias IS NOT NULL AND m.meta_dias > 0
    THEN ROUND(m.meta_dias / v.ii_d, 4)
    ELSE NULL
  END
FROM new_periodo np
CROSS JOIN (VALUES
    ${secVals}
) AS v(seccion, total_examenes, ir_h, rv_h, iv_h, vi_h, ii_h, ir_d, rv_d, iv_d, vi_d, ii_d)
LEFT JOIN metas_seccion m ON UPPER(TRIM(m.seccion)) = UPPER(TRIM(v.seccion))
ON CONFLICT (periodo_id, seccion)
DO UPDATE SET
  total_examenes = EXCLUDED.total_examenes,
  ingreso_resultado_horas = EXCLUDED.ingreso_resultado_horas,
  resultado_validacion_horas = EXCLUDED.resultado_validacion_horas,
  ingreso_validacion_horas = EXCLUDED.ingreso_validacion_horas,
  validacion_impresion_horas = EXCLUDED.validacion_impresion_horas,
  ingreso_impresion_horas = EXCLUDED.ingreso_impresion_horas,
  ingreso_resultado_dias = EXCLUDED.ingreso_resultado_dias,
  resultado_validacion_dias = EXCLUDED.resultado_validacion_dias,
  ingreso_validacion_dias = EXCLUDED.ingreso_validacion_dias,
  validacion_impresion_dias = EXCLUDED.validacion_impresion_dias,
  ingreso_impresion_dias = EXCLUDED.ingreso_impresion_dias,
  meta_dias = EXCLUDED.meta_dias,
  eficacia = EXCLUDED.eficacia;
`;

// --- SQL: Borrar examenes previos de este periodo ---
const deleteExamsSQL = `
DELETE FROM tiempos_examen
WHERE periodo_id = (
  SELECT id FROM periodos
  WHERE fecha_inicio = '${fechaInicio}' AND fecha_fin = '${fechaFin}'
);
`;

// --- SQL: Examenes ---
let examSQL = '';
if (todosExamenes.length > 0) {
  const examVals = todosExamenes.map(e =>
    `('${esc(e.seccionPadre)}', '${esc(e.examen)}', ${e.total}, '${esc(e.ingRes)}', '${esc(e.resVal)}', '${esc(e.ingVal)}', '${esc(e.valImp)}', '${esc(e.ingImp)}', ${timeToDays(e.ingRes)}, ${timeToDays(e.resVal)}, ${timeToDays(e.ingVal)}, ${timeToDays(e.valImp)}, ${timeToDays(e.ingImp)})`
  ).join(',\n      ');

  examSQL = `
WITH periodo AS (
  SELECT id FROM periodos
  WHERE fecha_inicio = '${fechaInicio}' AND fecha_fin = '${fechaFin}'
  LIMIT 1
)
INSERT INTO tiempos_examen (
  periodo_id, seccion_padre, examen, total_examenes,
  ingreso_resultado_horas, resultado_validacion_horas, ingreso_validacion_horas,
  validacion_impresion_horas, ingreso_impresion_horas,
  ingreso_resultado_dias, resultado_validacion_dias, ingreso_validacion_dias,
  validacion_impresion_dias, ingreso_impresion_dias
)
SELECT
  p.id, v.seccion_padre, v.examen, v.total_examenes,
  v.ir_h, v.rv_h, v.iv_h, v.vi_h, v.ii_h,
  v.ir_d, v.rv_d, v.iv_d, v.vi_d, v.ii_d
FROM periodo p
CROSS JOIN (VALUES
      ${examVals}
) AS v(seccion_padre, examen, total_examenes, ir_h, rv_h, iv_h, vi_h, ii_h, ir_d, rv_d, iv_d, vi_d, ii_d);
`;
}

const info = {
  periodo: mes + ' ' + anio,
  totalSecciones: secciones.length,
  secciones: secciones.map(s => s.seccion),
  totalExamenes: todosExamenes.length,
  errores: errores.length > 0 ? errores : undefined,
  fileName: fileName
};

const output = [
  { json: { valid: true, query: sectionSQL, info: info } }
];
if (todosExamenes.length > 0) {
  output.push({ json: { valid: true, query: deleteExamsSQL } });
  output.push({ json: { valid: true, query: examSQL } });
}
return output;

} catch (err) {
  return [{ json: { valid: false, errorMessage: 'Error procesando archivo: ' + err.message } }];
}

const info = $('Parsear y Transformar').first().json.info || {};
let msg = 'Procesado: ' + (info.totalSecciones || 0) + ' secciones, ' + (info.totalExamenes || 0) + ' examenes - ' + (info.periodo || '');
if (info.errores) msg += ' (advertencias: ' + info.errores.join('; ') + ')';
return [{ json: {
  success: true,
  message: msg,
  details: info
}}];

const errorMsg = $input.first().json.errorMessage || 'Error desconocido';
return [{ json: {
  success: false,
  message: errorMsg
}}];
